+            case.name.as_str(),
+            mode,
+            optimizer_evidence_refs(),
+            format!(
+                "cargo test -p ft-conformance strict_optimizer_conformance_is_green -- --nocapture # mode={}",
+                mode_label(mode)
+            ),
+            if params_ok { "pass" } else { "fail" },
+            reason_code.to_string(),
+        )
+        .with_extra_fields(extra_fields),
+    })
